import{_ as e,c as a,o,a2 as t,ao as r}from"./chunks/framework.VipzY1JJ.js";const m=JSON.parse('{"title":"Data & Observations Overview","description":"","frontmatter":{},"headers":[],"relativePath":"observations/index.md","filePath":"observations/index.md"}'),s={name:"observations/index.md"},n=t('<h1 id="data-observations-overview" tabindex="-1">Data &amp; Observations Overview <a class="header-anchor" href="#data-observations-overview" aria-label="Permalink to &quot;Data &amp; Observations Overview&quot;">​</a></h1><p>Arcsecond aims at providing a consistent platform for astronomical observers, being single or grouped into an organisation (such as an astronomy club, or an observatory - see <a href="/portals/">Observatory Portals</a> made for that).</p><p>As such, Arcsecond offers solutions for astronomical data alone, for observations alone, and for the combination of the two (where things become clearly more interesting).</p><h2 id="arcsecond-cloud-storage-vs-external-storages" tabindex="-1">Arcsecond Cloud Storage vs External Storages <a class="header-anchor" href="#arcsecond-cloud-storage-vs-external-storages" aria-label="Permalink to &quot;Arcsecond Cloud Storage vs External Storages&quot;">​</a></h2><p>The principle is the following. With each personal account, and identically, with each Observatory Portal, comes the <a href="./cloud-storage">Arcsecond Cloud storage</a> by default. It is an unlimited read-write storage (you can upload, modify, delete your files) based on secured Amazon AWS S3 buckets.</p><p>In addition to that, multiple External Storages can be attached to the above account or portal. There is no restrictions on the number of storages one can attach to an account or portal. These are read-only storages and Arcsecond will not modify anything in them. Credentials will have to be provided, and will be stored encrypted and securely sealed in Arcsecond (<a href="./credentials-security">read more</a>).</p><p>Find tutorials on how to provide credentials for your external storages in:</p><ul><li><a href="./external-storage-aws">Amazon AWS S3 buckets</a></li><li><a href="./external-storage-dropbox">Dropbox</a></li><li>FTP (coming soon)</li><li>Local disk (coming with self-hosted Arcsecond, later in 2023)</li></ul><p>For each account or portal, based on the accessible storages, Arcsecond will be able to extract and organise information about your nights and observed targets.</p><p><img src="'+r+'" alt="Overview of Observations &amp; Data" data-zoomable=""></p><p>Arcsecond will parse content of external storages, identically to what it does on its own <a href="/observations/cloud-storage">Cloud Storage</a> when data is uploaded to it. This parsing allows to:</p><ul><li>Extract FITS- and XISF-files headers, for easy searching in a web interface,</li><li>Create 2D-image and 1D-spectrum previews (stored in Arcsecond Cloud storage, within the 50GB limit, unless you unlock more),</li><li><strong>Create your personal list of all your observed targets, associated with its data</strong> (this will combine all cloud and external storages you have attached),</li><li>Reconstruct your observing nights (when possible).</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>We are working on an option to restrict the parsing to specific (sub)folder(s).</p></div>',13),i=[n];function l(c,d,h,p,u,b){return o(),a("div",null,i)}const v=e(s,[["render",l]]);export{m as __pageData,v as default};
